:root {
  --color-card-bg: #ffffff;
  --color-header-bg: #1a1a2e;
  --color-header-text: #ffffff;
  --color-gym-label: #a78bfa;
  --color-title: #ffffff;
  --color-badge-bg: #a78bfa;
  --color-badge-text: #1a1a2e;
  --color-yoga-accent: #34d399;
  --color-spin-accent: #f97316;
  --color-hiit-accent: #f43f5e;
  --color-pilates-accent: #60a5fa;
  --color-boxing-accent: #fbbf24;
  --color-item-bg: #f8f7ff;
  --color-item-border: #e9e7f5;
  --color-time-text: #374151;
  --color-name-text: #111827;
  --color-meta-text: #6b7280;
  --color-spots-text: #059669;
  --color-spots-bg: #d1fae5;
  --color-full-text: #dc2626;
  --color-full-bg: #fee2e2;
  --color-footer-bg: #f3f2fc;
  --color-legend-text: #6b7280;
  --color-dot-low: #fbbf24;
  --color-dot-full: #dc2626;
  --color-btn-bg: #a78bfa;
  --color-btn-text: #1a1a2e;
}

.schedule-card {
  width: 480px;
  background: var(--color-card-bg);
  border-radius: 16px;
  overflow: hidden;
  border: 1px solid var(--color-item-border);
}

.card-header {
  background: var(--color-header-bg);
  padding: 16px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.gym-label {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 2px;
  color: var(--color-gym-label);
}

.card-title {
  font-size: 20px;
  font-weight: 700;
  color: var(--color-title);
  margin: 0;
}

.day-badge {
  background: var(--color-badge-bg);
  color: var(--color-badge-text);
  font-size: 13px;
  font-weight: 800;
  letter-spacing: 1px;
  padding: 8px 14px;
  border-radius: 8px;
}

.class-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 12px 16px;
}

.class-item {
  display: flex;
  align-items: center;
  gap: 12px;
  background: var(--color-item-bg);
  border: 1px solid var(--color-item-border);
  border-radius: 10px;
  padding: 10px 14px;
  border-left-width: 4px;
}

.class-yoga { border-left-color: var(--color-yoga-accent); }
.class-spin { border-left-color: var(--color-spin-accent); }
.class-hiit { border-left-color: var(--color-hiit-accent); }
.class-pilates { border-left-color: var(--color-pilates-accent); }
.class-boxing { border-left-color: var(--color-boxing-accent); }

.class-time {
  font-size: 13px;
  font-weight: 700;
  color: var(--color-time-text);
  width: 42px;
  flex-shrink: 0;
}

.class-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
  flex: 1;
}

.class-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--color-name-text);
}

.class-meta {
  font-size: 11px;
  color: var(--color-meta-text);
}

.class-spots {
  font-size: 11px;
  font-weight: 700;
  color: var(--color-spots-text);
  background: var(--color-spots-bg);
  padding: 3px 8px;
  border-radius: 20px;
  white-space: nowrap;
}

.class-spots.full {
  color: var(--color-full-text);
  background: var(--color-full-bg);
}

.card-footer {
  background: var(--color-footer-bg);
  padding: 10px 16px;
  display: flex;
  align-items: center;
  gap: 16px;
}

.legend-item {
  display: flex;
  align-items: center;
  gap: 5px;
}

.legend-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}

.dot-low { background: var(--color-dot-low); }
.dot-full { background: var(--color-dot-full); }

.legend-text {
  font-size: 11px;
  color: var(--color-legend-text);
}

.book-btn {
  margin-left: auto;
  background: var(--color-btn-bg);
  color: var(--color-btn-text);
  font-size: 12px;
  font-weight: 700;
  padding: 7px 16px;
  border-radius: 8px;
  border: none;
  cursor: pointer;
}
